Extract data from the following document based on the JSON schema.
Return null if the document does not contain information relevant to schema.
Return only the JSON with no explanation text.
The JSON schema is as follows:
{
  "type": "object",
  "properties": {
    "vehicles": {
      "type": "array",
      "items": {
        "type": "object",
        "properties": {
          "info": {
            "type": "object",
            "properties": {
              "name": {
                "type": "string",
                "description": "vehicle name, without year"
              },
              "year": {
                "type": "number",
                "description": ""
              },
              "additional_details": {
                "type": "string",
                "description": ""
              }
            }
          },
          "facts": {
            "type": "object",
            "properties": {
              "mileage": {
                "type": "string",
                "description": ""
              },
              "drivetrain": {
                "type": "string",
                "description": ""
              },
              "horsepower": {
                "type": "string",
                "description": ""
              },
              "engine_type": {
                "type": "string",
                "description": ""
              },
              "transmission": {
                "type": "string",
                "description": ""
              },
              "seating_capacity": {
                "type": "number",
                "description": ""
              }
            },
            "description": ""
          },
          "pricing": {
            "type": "object",
            "properties": {
              "MSRP": {
                "type": "number",
                "description": ""
              },
              "invoice": {
                "type": "number",
                "description": ""
              },
              "destination": {
                "type": "number",
                "description": ""
              }
            },
            "description": ""
          },
          "warranty": {
            "type": "object",
            "properties": {
              "basic": {
                "type": "string",
                "description": ""
              },
              "drivetrain": {
                "type": "string",
                "description": ""
              },
              "roadside_assistance": {
                "type": "string",
                "description": ""
              }
            },
            "description": ""
          }
        }
      }
    }
  }
}
